  const lines = [prompt, '', 'Adjuntos disponibles en disco local del servidor:'];
  attachments.forEach((file, idx) => {
    lines.push(`${idx + 1}. ${file.name} (${file.mimeType}, ${file.size} bytes) -> ${file.path}`);
    if (file.previewText) {
      lines.push(`Contenido de ${file.name}:`);
      lines.push('```');
